import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BwNZcjNV.js";const u=JSON.parse('{"title":"수납 고지서 관리","description":"","frontmatter":{},"headers":[],"relativePath":"notice/bill.md","filePath":"notice/bill.md","lastUpdated":1784221072000}'),i={name:"notice/bill.md"};function n(o,t,d,s,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="수납-고지서-관리" tabindex="-1">수납 고지서 관리 <a class="header-anchor" href="#수납-고지서-관리" aria-label="Permalink to &quot;수납 고지서 관리&quot;">​</a></h1><p>프로젝트의 납부 회차별 대금 수납 고지서를 생성하고 발행 정보를 관리하는 페이지입니다.</p><ul><li><strong>위치</strong>: <code>고객 고지 관리 &gt; 수납 고지서 출력</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>특정 납부 회차(계약금, 중도금 등)에 대한 고지서를 발행하기 위해 시행사 정보, 수납 계좌, 안내 문구 등을 설정합니다. 설정된 정보를 바탕으로 계약자별 납부 현황(완납/미납)을 확인하고, 선택한 계약자들에 대한 고지서를 PDF 파일로 일괄 생성하여 다운로드할 수 있습니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li>고지서 기본 정보(발행자, 연락처, 주소 등) 및 수납 계좌 설정</li><li>발행 대상 회차 및 해당 회차의 납부 기한 지정</li><li>차수, 타입, 동호수별 계약자 필터링 및 검색</li><li>회차별 납입 상태(완납/미납) 시각적 확인</li><li>선택 건별 고지서 PDF 일괄 생성 및 다운로드</li><li>고지서 출력 시 가격 정보 또는 연체 정보 숨김 옵션 제공</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-고지서-발행-정보-설정" tabindex="-1">1. 고지서 발행 정보 설정 <a class="header-anchor" href="#_1-고지서-발행-정보-설정" aria-label="Permalink to &quot;1. 고지서 발행 정보 설정&quot;">​</a></h3><p>고지서의 상단과 하단에 표시될 공식 정보와 수납을 위한 금융 정보를 입력합니다.</p><h4 id="주요-입력-항목" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">발행일자</td><td style="text-align:center;">필수</td><td style="text-align:left;">고지서 상단에 표시될 공식 발행 날짜</td></tr><tr><td style="text-align:left;">발행회차</td><td style="text-align:center;">필수</td><td style="text-align:left;">현재 고지서를 발행할 대상 납부 회차 선택</td></tr><tr><td style="text-align:left;">당회 납부기한</td><td style="text-align:center;"></td><td style="text-align:left;">해당 회차의 입금 마감 기일 (회차 정보에 자동 연동 가능)</td></tr><tr><td style="text-align:left;">시행자/대행사 정보</td><td style="text-align:center;">필수</td><td style="text-align:left;">고지 주체의 명칭 및 공식 연락처</td></tr><tr><td style="text-align:left;">수납은행(1, 2)</td><td style="text-align:center;">필수</td><td style="text-align:left;">분양 대금을 수납할 은행, 계좌번호 및 예금주 (최대 2개)</td></tr><tr><td style="text-align:left;">시행자 주소</td><td style="text-align:center;">필수</td><td style="text-align:left;">고지서에 표시될 시행사(또는 사업단)의 공식 주소</td></tr><tr><td style="text-align:left;">고지서 제목/내용</td><td style="text-align:center;">필수</td><td style="text-align:left;">고지서 중앙에 표시될 안내 제목과 상세 공지 문구</td></tr></tbody></table><blockquote><p><strong>참고</strong>: 고지서를 출력하기 위해서는 반드시 이 설정 데이터를 먼저 [저장]해야 합니다.</p></blockquote><h3 id="_2-목록-제어-및-필터링" tabindex="-1">2. 목록 제어 및 필터링 <a class="header-anchor" href="#_2-목록-제어-및-필터링" aria-label="Permalink to &quot;2. 목록 제어 및 필터링&quot;">​</a></h3><p>고지서를 발송할 대상 계약자를 찾기 위한 조건을 설정합니다.</p><ul><li><strong>필터 항목</strong>: 차수, 타입, 동 선택 및 계약자명/일련번호 검색 지원</li><li><strong>회차 정보 표시</strong>: 현재 발행 설정된 회차 명칭이 상단에 강조 표시되어 대상을 혼동하지 않도록 돕습니다.</li></ul><h3 id="_3-고지서-다운로드-옵션" tabindex="-1">3. 고지서 다운로드 옵션 <a class="header-anchor" href="#_3-고지서-다운로드-옵션" aria-label="Permalink to &quot;3. 고지서 다운로드 옵션&quot;">​</a></h3><p>선택된 계약자들에 대한 PDF 생성 조건을 지정합니다.</p><ul><li><strong>가격정보 미표시</strong>: 체크 시 고지서에서 상세 분양가 및 납부 가액 정보를 숨깁니다.</li><li><strong>연체정보 미표시</strong>: 체크 시 미납으로 인한 연체료 계산 정보를 제외하고 출력합니다.</li></ul><h3 id="_4-계약-목록-및-선택" tabindex="-1">4. 계약 목록 및 선택 <a class="header-anchor" href="#_4-계약-목록-및-선택" aria-label="Permalink to &quot;4. 계약 목록 및 선택&quot;">​</a></h3><p>계약자별 현재 수납 상태를 확인하고 고지서를 발행할 대상을 선택합니다.</p><ul><li><strong>납입상태 표시</strong>: 설정된 &#39;발행회차&#39;를 기준으로 해당 회차까지 돈을 모두 냈는지(<strong>완납중</strong>) 아니면 부족한지(<strong>미납중</strong>)를 자동으로 판별하여 표시합니다.</li><li><strong>선택 제어</strong>: 이미 완납된 계약자는 고지서 발행 대상에서 제외되도록 체크박스가 비활성화됩니다. (전체 선택 시에도 미납자만 선택됨)</li></ul><h2 id="💡-업무-팁" tabindex="-1">💡 업무 팁 <a class="header-anchor" href="#💡-업무-팁" aria-label="Permalink to &quot;💡 업무 팁&quot;">​</a></h2><ul><li><strong>회차 기한 업데이트</strong>: [고지서 발행 정보 설정]에서 &#39;당회 납부기한&#39;을 수정하고 저장하면, 연결된 [납부 회차 등록]의 약정일 데이터도 함께 업데이트되어 관리가 편리합니다.</li><li><strong>테스트 출력</strong>: 대량 발행 전 1~2건의 계약자만 선택하여 PDF 레이아웃과 오타 여부를 먼저 확인하는 것이 좋습니다.</li></ul>',24)])])}const x=e(i,[["render",n]]);export{u as __pageData,x as default};
